const crypto = require('crypto');
const sig = $node['Webhook: Product Published'].json.headers['x-printhub-signature'];
const hmac = crypto.createHmac('sha256', process.env.N8N_WEBHOOK_SECRET).update(JSON.stringify($node['Webhook: Product Published'].json.body)).digest('hex');
if (sig !== hmac) throw new Error('Invalid signature');
return $node['Webhook: Product Published'].json.body;

const crypto = require('crypto');
const sig = $node['Webhook or Execute Trigger'].json.headers['x-printhub-signature'];
const hmac = crypto.createHmac('sha256', process.env.N8N_WEBHOOK_SECRET).update(JSON.stringify($node['Webhook or Execute Trigger'].json.body)).digest('hex');
if (sig !== hmac) throw new Error('Invalid signature');
return $node['Webhook or Execute Trigger'].json.body;

const { productId, productName, category, platform } = $json;
const cat = category || 'product';
const instagramPrompt = `Professional lifestyle photograph of ${productName} in a modern Nairobi home or office setting. Clean, bright, aspirational. The ${cat} is displayed prominently. Warm Kenyan interior aesthetics. Shot on Canon 5D, f/2.8, natural light. No text, no watermarks, no people.`;
const linkedinPrompt = `Professional corporate photograph of ${productName} in a modern Nairobi office environment. Clean desk setup, corporate aesthetic. Professional lighting. B2B context. No text, no watermarks.`;
const tiktokPrompt = `Vibrant, eye-catching flat lay of ${productName}. Colourful props, trendy aesthetic, Gen-Z appeal. African textile patterns as background. Bright natural light. No text, no watermarks.`;
return [{ productId, productName, category, instagramPrompt, linkedinPrompt, tiktokPrompt }];

const productId = $node['Build DALL-E Prompts'].json.productId;
const instagramPrompt = $node['Build DALL-E Prompts'].json.instagramPrompt;
const dalleIG = $node['DALL-E 3: Instagram Mockup'].json.data?.[0]?.url;
const dalleLinkedIn = $node['DALL-E 3: LinkedIn Mockup'].json.data?.[0]?.url;
const dalleTikTok = $node['DALL-E 3: TikTok Mockup'].json.data?.[0]?.url;
const stabilityImages = $node['Stability AI: Variations'].json.artifacts || [];
const imageUrls = [
  dalleIG ? { url: dalleIG, platform: 'instagram', generator: 'dalle3', prompt: instagramPrompt } : null,
  dalleLinkedIn ? { url: dalleLinkedIn, platform: 'linkedin', generator: 'dalle3', prompt: $node['Build DALL-E Prompts'].json.linkedinPrompt } : null,
  dalleTikTok ? { url: dalleTikTok, platform: 'tiktok', generator: 'dalle3', prompt: $node['Build DALL-E Prompts'].json.tiktokPrompt } : null,
  ...stabilityImages.map((img, i) => img.base64 ? null : { url: `data:image/png;base64,${img.base64}`, platform: 'variation', generator: 'stabilityai', prompt: instagramPrompt + ' variation ' + (i+1) })
].filter(Boolean);
return [{ productId, imageUrls }];

const crypto = require('crypto');
const sig = $node['Webhook: Generate Video'].json.headers['x-printhub-signature'];
const hmac = crypto.createHmac('sha256', process.env.N8N_WEBHOOK_SECRET).update(JSON.stringify($node['Webhook: Generate Video'].json.body)).digest('hex');
if (sig !== hmac) throw new Error('Invalid signature');
return $node['Webhook: Generate Video'].json.body;

const raw = $node['Claude: Write Video Script'].json.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || raw); } catch { parsed = { script: raw, hook: '', cta: '' }; }
return [{ ...$node['Verify Signature'].json, script: parsed.script, hook: parsed.hook, cta: parsed.cta }];

const isVoice = $node['Is Voice Note?'].json.message?.voice?.file_id !== undefined;
const text = isVoice ? $node['Whisper: Transcribe'].json.text : $node['Is Voice Note?'].json.message?.text;
const chatId = ($node['Is Voice Note?'].json.message?.chat?.id || '').toString();
const customerName = $node['Is Voice Note?'].json.message?.from?.first_name || 'Customer';
return [{ messageText: text, chatId, customerName, wasVoiceNote: isVoice }];

const jwt = require('jsonwebtoken');
const header = { alg: 'ES256', kid: process.env.APPLE_KEY_ID };
const payload = { iss: process.env.APPLE_TEAM_ID, iat: Math.floor(Date.now()/1000), exp: Math.floor(Date.now()/1000)+1800, origin: 'https://printhub.africa' };
const privateKey = Buffer.from(process.env.APPLE_PRIVATE_KEY, 'base64').toString();
return [{ token: jwt.sign(payload, privateKey, { header }) }];

